    pub fn parse_currency(&self, mut rawCurrency: Value) -> Value {
        let mut currencyId: Value = self.safe_string_k(rawCurrency.clone(), "currency", &[]);
        let mut code: Value = self.safe_currency_code(currencyId.clone(), &[]);
        return self.safe_currency_structure(Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("info".to_string(), rawCurrency.clone());
        m.insert("code".to_string(), code.clone());
        m.insert("id".to_string(), currencyId.clone());
        m.insert("name".to_string(), self.safe_string_k(rawCurrency.clone(), "currency_long", &[]));
        m.insert("active".to_string(), Value::Null);
        m.insert("deposit".to_string(), Value::Null);
        m.insert("withdraw".to_string(), Value::Null);
        m.insert("type".to_string(), Value::Str("crypto".to_string()));
        m.insert("fee".to_string(), self.safe_number_k(rawCurrency.clone(), "withdrawal_fee", &[]));
        m.insert("precision".to_string(), Value::Null);
        m.insert("limits".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("amount".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("min".to_string(), Value::Null);
        m.insert("max".to_string(), Value::Null);
    m
}));
        m.insert("withdraw".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("min".to_string(), Value::Null);
        m.insert("max".to_string(), Value::Null);
    m
}));
        m.insert("deposit".to_string(), Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("min".to_string(), Value::Null);
        m.insert("max".to_string(), Value::Null);
    m
}));
    m
}));
        m.insert("networks".to_string(), Value::Null);
    m
}));

    Value::Null
}

    pub fn code_from_options(&self, mut methodName: Value, optional_args: &[Value]) -> Value {
        let mut params = get_arg(optional_args, 0, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        let mut defaultCode: Value = self.safe_value_k(self.options.clone(), "code", &[Value::Str("BTC".to_string())]);
        let mut options: Value = self.safe_value(self.options.clone(), methodName.clone(), &[Value::Map({
            let mut m = indexmap::IndexMap::new();
            m
        })]);
        let mut code: Value = self.safe_value_k(options.clone(), "code", &[defaultCode.clone()]);
        return self.safe_value_k(params.clone(), "code", &[code.clone()]);

    Value::Null
}

/*
 * @method
 * @name deribit#fetchStatus
 * @description the latest known information on the availability of the exchange API
 * @see https://docs.deribit.com/#public-status
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @returns {object} a [status structure]{@link https://docs.ccxt.com/?id=exchange-status-structure}
 */
    pub async fn fetch_status(&mut self, optional_args: &[Value]) -> Value {
        let mut params = get_arg(optional_args, 0, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        let mut response: Value = self.public_get_status(&[params.clone()]).await;
        //
        //     {
        //         "jsonrpc": "2.0",
        //         "result": {
        //             "locked": "false" // true, partial, false
        //         },
        //         "usIn": 1650641690226788,
        //         "usOut": 1650641690226836,
        //         "usDiff": 48,
        //         "testnet": false
        //     }
        //
        let mut result: Value = self.safe_value_k(response.clone(), "result", &[]);
        let mut locked: Value = self.safe_string_k(result.clone(), "locked", &[]);
        let mut updateTime: Value = self.safe_integer_product(response.clone(), Value::Str("usIn".to_string()), Value::Float(0.001), &[self.milliseconds()]);
        return Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("status".to_string(), ternary(is_true(&(is_equal(&locked, &Value::Str("false".to_string())))), Value::Str("ok".to_string()), Value::Str("maintenance".to_string())));
        m.insert("updated".to_string(), updateTime.clone());
        m.insert("eta".to_string(), Value::Null);
        m.insert("url".to_string(), Value::Null);
        m.insert("info".to_string(), response.clone());
    m
});

    Value::Null
}

