    pub fn parse_open_interest(&self, mut interest: Value, optional_args: &[Value]) -> Value {
        let mut market = get_arg(optional_args, 0, Value::Null);
        //
        //     {
        //         "high": 93099.5,
        //         "low": 81773.0,
        //         "last": 87197.0,
        //         "instrument_name": "BTC-PERPETUAL",
        //         "bid_price": 87083.0,
        //         "ask_price": 87149.5,
        //         "open_interest": 9978911260,
        //         "mark_price": 87102.01,
        //         "creation_timestamp": 1763674177068,
        //         "price_change": -3.2032,
        //         "volume": 7377.18657991,
        //         "estimated_delivery_price": 87047.2,
        //         "base_currency": "BTC",
        //         "quote_currency": "USD",
        //         "volume_usd": 661040250.0,
        //         "volume_notional": 661040250.0,
        //         "current_funding": 1.2966e-4,
        //         "funding_8h": -8.1069e-4,
        //         "mid_price": 87116.25
        //     }
        //
        let mut timestamp: Value = self.safe_integer_k(interest.clone(), "creation_timestamp", &[]);
        let mut marketId: Value = self.safe_string_k(interest.clone(), "instrument_name", &[]);
        market = self.safe_market(&[marketId.clone(), market.clone()]);
        let mut openInterest: Value = self.safe_number_k(interest.clone(), "open_interest", &[]);
        let mut openInterestAmount: Value = Value::Null;
        let mut openInterestValue: Value = Value::Null;
        if is_true(&get_value(&market, &Value::Str("option".to_string()))) || is_true(&(is_true(&get_value(&market, &Value::Str("future".to_string()))) && is_true(&get_value(&market, &Value::Str("linear".to_string()))))) {
            openInterestAmount = openInterest.clone();
        }  else {
            openInterestValue = openInterest.clone();
        }
        return self.safe_open_interest(Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("symbol".to_string(), self.safe_symbol(marketId.clone(), &[market.clone()]));
        m.insert("openInterestAmount".to_string(), openInterestAmount.clone());
        m.insert("openInterestValue".to_string(), openInterestValue.clone());
        m.insert("timestamp".to_string(), timestamp.clone());
        m.insert("datetime".to_string(), self.iso8601(timestamp.clone()));
        m.insert("info".to_string(), interest.clone());
    m
}), &[market.clone()]);

    Value::Null
}

